INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-01117', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於病例對照研究（case-controlstudies）下列何者錯誤？', '["研究者可以決定一個病例選一個對照，或一病例選二個對照，或更多對照，對照/病例的比 越高，研究檢力越高，若是經費充足，則對照/病例的比達5或更高更好", "進行配對病例對照研究，以A變項當作配對條件，則此研究無法探討A變項與該研究疾病 之相關", "以病例對照研究探討兒童腦癌和母親懷孕時的輻射暴露，研究以不同類型多重對照的設計， 選一組患其他癌症的兒童當對照，另一組對照是健康的兒童，這樣的設計降低回憶偏差作 用的可能性", "若記憶力的侷限（limitationofrecall）對每個研究對象（不論病例或對照）達相同程度影響， 這將造成暴露狀態的錯誤分組，若是暴露只有兩組（有、無），則研究結果低估 （underestimate）暴露對疾病造成的風險，傾向趨零偏差（biastowardanull）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01118', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '研究員欲探討「稀有職業暴露（如太空人暴露宇宙輻射）」與疾病的關聯。此種主題較適合利 用何種研究進行探討？', '["病例對照研究", "前瞻性世代研究", "生態學研究", "隨機對照試驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01119', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '進行一個1：1個別配對病例對照研究（amatched-pairscase-controlstudy），結果發現：病例 對照皆暴露者有5對；病例對照皆無暴露者有5對；病例有暴露但對照無暴露者有9對；病 例無暴露但對照有暴露者有1對，請計算配對的勝算比為何？', '["5.44", "0.18", "9.00", "0.11"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01120', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '病例對照研究挑選對照組來源的條件，下列四者中，何者最不重要？', '["選樣條件不應與研究假說中的危險因子有關", "與病例個案組來自同樣的目標族群", "其暴露測量的測量誤差應與病例組的暴露測量誤差相近", "干擾因子的分布要與病例組相像"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01121', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '進行一個隨機分派的臨床試驗研究，若出現計畫外的交叉（unplannedcrossover），計畫外的交 叉對資料分析構成嚴重的挑戰，下列敘述何者錯誤？', '["意向性分析（intentiontotreatanalysis）保留了原來隨機分派的設計優勢，但可能低估療效", "根據治療分析（treatedanalysis）將病人按照其實際接受的治療方案進行分組，進行分析， 可以更精確地評估特定治療方案的有效性，是初步分析（primaryanalysis）所採用的方法也 是最完美的分析方法", "符合計畫書分析（per-protocolanalysis）只分析那些完全按照研究方案和治療計畫完成試驗 的病人，但可能存在選擇性偏差（selectionbias）", "上述三種分析方法結果差異大，表示計畫外的交叉數多"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01122', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於訊息偏差（informationbias），下列敘述何者錯誤？', '["回憶偏差（recallbias）是一種訊息偏差（informationbias）", "差別性分類錯誤（differentialmisclassification）可能造成原本無相關變成有相關，或原本有 相關變成無相關", "若有三組暴露組（例如：輕度、中度、重度吸菸），無差別性分類錯誤（nondifferential misclassification）對相對危險性（relativerisk,RR）或勝算比（oddsratio,OR）的影響是趨 向1", "想要興訟的人，過度強調職場有關的暴露，這是願望偏差（wishbias），是報告偏差（reporting bias）的一種"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01123', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '美國生理學家Ancel Keys在20世紀中葉發現歐洲各國飲食用油不同，而且各國的心血管死 亡率有明顯差距，因此引發一系列食用油脂種類與心血管疾病關聯性的論點。下列四則評論 中，何者最不適當？', '["他的推論來自於生態研究", "這類的觀察需確認國家之間是否還有其他差異，例如其他與心血管疾病風險有關的飲食成 分也有國際差異", "這類研究觀察到的證據中會有回憶偏誤的問題（recallbias）", "國家群集層次的相關性不一定能直接推導到個人層次的相關性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01124', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '群體免疫力（herdimmunity）的存在有賴於某些條件，下列何者不是？', '["病原僅限於在單一物種內傳播", "病原從一個宿主直接傳播給另一宿主", "病原能誘發宿主堅固的免疫力（solidimmunity）", "一個有感染力的宿主遇到族群中的每個人機率不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01125', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '進行一個世代研究，無暴露到 B 型肝炎病毒（HBV）也無暴露到黃麴毒素（aflatoxin）者， 每10萬人肝癌發生率是3；暴露到B型肝炎病毒（HBV）但無暴露到黃麴毒素（aflatoxin）者， 每10萬人肝癌發生率是24；無暴露到B型肝炎病毒（HBV）但是暴露到黃麴毒素（aflatoxin） 者，每10萬人肝癌發生率是9；暴露到B型肝炎病毒（HBV）也暴露到黃麴毒素（aflatoxin） 者，每10萬人肝癌發生率是180，此研究中B型肝炎病毒和黃麴毒素對肝癌的影響是？', '["加成性協同作用但是累乘性獨立作用", "加成性協同作用且是累乘性協同作用", "加成性獨立作用但是累乘性協同作用", "加成性獨立作用且是累乘性獨立作用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01126', 'public-health-specialist', 'public-health-specialist-moex-114-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '篩檢工具甲的敏感度與特異度皆為90%，篩檢工具乙的敏感度與特異度分別為95%與85%。 若施用在一個疾病盛行率為20%的族群，下列選項何者正確？', '["如果以系列篩檢的方式進行，淨敏感度會高於甲的敏感度，淨特異度會低於乙的特異度", "如果以平行篩檢的方式進行，淨敏感度會高於乙的敏感度，淨特異度會低於甲的特異度", "如果以系列篩檢的方式進行，淨假陰性率會低於單獨使用甲時的假陰性率", "如果以平行篩檢的方式進行，淨假陰性率會高於單獨使用乙時的假陰性率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "5aad29b928bd", "answer_pdf_sha1": "36cab4a52ac0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
